"""
MKT Context Commentary — Exodus chapters 19–21
Run: python3 scripts/zc-context-exodus-19-21-fill.py

Source data used:
- data/interlinear/exodus.json
- data/translation/draft/mediating/exodus.json

Key decisions in this range:
- Ch19 v.1 already present — script covers v.2-25
- Decalogue (ch20) treated within ANE suzerain-vassal treaty form (Mendenhall/Kline framework)
- Lex talionis (21:23-25) treated as proportionality principle, not individual-revenge license
- 30-shekel ox-goring payment (21:32) noted as the figure that runs through Zech 11:12-13 and Matt 26:15
- Mishpatim framed as case-law applications of Decalogue principles
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EXODUS = {
"19": {
"2": "<p>They had journeyed from Rephidim (possibly the Wadi Feiran area in the Sinai) and arrived in the Sinai wilderness. The traditional identification of Mount Sinai is Jebel Musa in the southern Sinai Peninsula (ca. 2,285m), the location venerated since the early Byzantine period and confirmed by St. Catherine's Monastery. An alternative identification places Sinai at Jebel al-Lawz in northwest Saudi Arabia. Israel camped at the foot of the mountain — the camp and the mountain are two zones of the encounter, with the mountain as the vertical axis connecting earth to the divine presence above.</p>",
"3": "<p>Moses went up to God, and YHWH called to him from the mountain. In ANE cosmology, mountains were the dwelling places of the gods — the high place where heaven and earth meet. Ugaritic literature describes Baal dwelling on Mount Zaphon; Sumerian texts locate divine temples as mountain replicas (ziggurats as artificial sacred mountains). YHWH's use of a mountain as the site of covenant communication operates within this recognizable religious geography while surpassing it: YHWH is not confined to the mountain but descends to it (v.18, 20). The covenant announced in v.3-6 follows the structure of ANE suzerain-vassal treaties (preamble, historical prologue, stipulations, blessings/curses).</p>",
"4": "<p>The eagle's wing metaphor — 'I carried you on eagles' wings and brought you to myself' — is developed more fully in Deut 32:10-11, where YHWH is like an eagle stirring its nest and bearing its young on its wings. The eagle carries its eaglets on its back to protect them from attack from below; if an arrow is shot at the young, it strikes the parent first. The metaphor claims that the Exodus was not Israel's achievement or even Moses' — it was YHWH's sovereign act of parental rescue. 'To myself' (<em>elay</em>): the goal of the Exodus was not Canaan but YHWH himself. The land is the means; the relationship is the end.</p>",
"5": "<p>Segullah — 'treasured possession' (H5459, appears only 8x in OT). In the ancient world, a king's <em>segullah</em> was his private treasury, his personally owned moveable wealth — not the national treasury but his personal reserve. The term appears in ANE royal inscriptions for a king's chosen people or city. YHWH claims Israel as his personal treasury among all the peoples — not because Israel is large or powerful but by covenantal election. The conditional structure ('if you truly obey my voice and keep my covenant') places this identity within the suzerain-vassal treaty form: the vassal's privileged status depends on fidelity to the great king's terms.</p>",
"6": "<p>Mamlekhet kohanim ve-goy qadosh — 'kingdom of priests and a holy nation.' Israel's national vocation is twofold: priestly (to mediate between YHWH and the nations) and holy (set apart, distinctive). The priestly role is corporate and international: as Aaron mediates between YHWH and Israel, so Israel mediates between YHWH and all nations. The term <em>goy qadosh</em> (holy nation) applies the cultic word for consecrated persons (<em>qadosh</em>) to the whole nation — all Israel, not just the Levites, is constituted as a priestly people. 1 Pet 2:9 applies this verse directly to the church in Christ: 'a royal priesthood, a holy nation.' The NT claim is that in Christ the vocation of Israel is extended to all who are grafted in.</p>",
"7": "<p>Moses convened the elders of Israel and set before them all these words — the covenant is presented through representative governance structures. The elders (<em>zeqenim</em>) are the tribal heads who constitute Israel's pre-monarchic political body. The covenant is communal: Moses does not present the terms to individuals but to the assembled representatives of the whole people. The covenant is accepted on behalf of the entire community, with implications that bind all generations.</p>",
"8": "<p>'All that YHWH has spoken we will do' (<em>kol asher diber YHWH na'aseh</em>) — the covenant ratification speech. The entire people respond together (<em>yachdav</em>). This communal acceptance formula will be formalized in blood at Ex 24:3-8 ('the blood of the covenant'). Significantly, the people commit to 'do' the covenant before they have heard all its detailed terms — the mishpatim (Ex 21-23) come after this acceptance, not before it. The sequence mirrors the NT structure: covenant relationship precedes law-keeping; grace is the ground, obedience the response.</p>",
"9": "<p>YHWH will come to Moses in a thick cloud (<em>anan av</em>) so the people can hear him speak with Moses — the cloud serves two functions: it conceals the divine form (no one can see YHWH and live, 33:20) while transmitting divine speech. The auditory theophany is specifically designed to validate Moses' prophetic authority in the eyes of the people: they hear YHWH speaking with Moses, which grounds their trust in subsequent Mosaic communication. The cloud is the technology of divine mediation — presence without visibility, communication without direct exposure.</p>",
"10": "<p>YHWH instructs Moses to consecrate the people — wash their clothes and be ready by the third day. The three-day preparation period creates liturgical anticipation and ritual purity. Washing clothes in the ANE was a standard purification rite before sacred events; the Levitical purity laws (which develop this much further) build on this practice. 'The third day' carries covenant weight throughout the OT: Abraham sees the mountain on the third day at the Aqedah (Gen 22:4); Jonah is in the fish three days; and the resurrection of the dead connects explicitly to this theophanic pattern (Hos 6:2; 1 Cor 15:4).</p>",
"11": "<p>On the third day YHWH will come down on Mount Sinai in the sight of all the people. The descent of YHWH to Sinai is described with the same verb (<em>yarad</em> = came down) used in 3:8 for the divine descent to deliver Israel. YHWH does not merely summon Israel upward but comes down to them — the pattern of divine condescension that characterizes the Exodus narrative as a whole. The 'sight of all the people' is the democratic dimension of the theophany: the covenant is not a private mystical experience for Moses but a public event witnessed by the entire community.</p>",
"12": "<p>Barriers are set around the mountain — anyone who touches the mountain must be put to death. The spatial holiness of Sinai anticipates the graduated access structure of the tabernacle: the outer court, holy place, and holy of holies correspond to the people's camp, the foot of the mountain, and the summit. Physical boundaries enforce theological realities: divine holiness is not safely approached without proper mediation. The lethal boundary teaches what the tabernacle will architecturally encode: nearness to the holy requires preparation, permission, and the right mediator.</p>",
"13": "<p>The method of execution for violating the boundary: stoning or shooting with arrows — at a distance, because even the executioner must not touch the boundary-violator (now ritually contaminated by touching the sacred zone without permission). When the long trumpet blast sounds, the people may go up. The trumpet (<em>yovel</em>, the ram's horn) signals the end of the dangerous divine approach and the beginning of sanctioned access. The Jubilee year is announced by the same instrument (Lev 25:9-10) — the trumpet of liberation and the trumpet of access are the same sound.</p>",
"14": "<p>Moses went down from the mountain to the people and consecrated them — he is the active agent of consecration, the mediator who prepares the people for the divine encounter. The people washed their clothes — in ancient Israelite practice, linen garments were associated with purity (cf. the white linen of the priests), while clothes contaminated by ordinary life required washing before any cultic event. The physical act of washing is not merely hygienic but symbolic: the outer act expresses an inner reorientation toward YHWH.</p>",
"15": "<p>'Be ready for the third day; do not approach a woman.' The requirement of sexual abstinence before a major cultic event is attested in multiple ANE contexts. It is not that sexuality is sinful but that the total dedication of the person to the moment of divine encounter requires temporary withdrawal from even lawful pleasures. Paul applies a similar principle in 1 Cor 7:5 — spouses may agree to temporary abstinence for prayer. The logic is concentration, not condemnation: the meeting with YHWH at Sinai requires the full attention of the whole self.</p>",
"16": "<p>On the morning of the third day — thunder, lightning, a thick cloud over the mountain, and the sound of a very loud trumpet (<em>shofar</em>). All the people in the camp trembled. The Sinai theophany employs the standard ANE storm-god imagery: thunder (<em>qolot</em> = voices/thunders), lightning (<em>beraqim</em>), thick cloud, fire, earthquake. The Baal cycle of Ugarit describes Baal as the storm-deity who speaks in thunder and lightning. YHWH appropriates this imagery while emptying it of Baal's content — this is not Baal's storm but YHWH's self-disclosure, which is why the theophany must be distinguished from all other storm experiences. The shofar (ram's horn) will later announce the Jubilee, the New Year, and royal accessions — the same instrument marks cosmic-covenantal transitions.</p>",
"17": "<p>Moses brought the people out of the camp to meet God — the pilgrimage from the camp (ordinary space) to the mountain (sacred space) is the structural movement of Israelite worship. The people take up their stations at the foot of the mountain. The Hebrew <em>lemrat haElohim</em> = 'to meet/confront God' — the word <em>liqrat</em> is used for the formal procession of one party to meet another (cf. Moses meeting his father-in-law in 18:7, Abraham meeting the kings in Gen 14:17). The encounter with YHWH at Sinai is a formal, procedural event — structured, not accidental.</p>",
"18": "<p>Sinai was covered with smoke because YHWH descended on it in fire — the fire and smoke column reactivates the imagery of the Exodus march (Ex 13:21-22, the pillar of fire and cloud). The comparison to a kiln (<em>kibshan</em>) may evoke the smoke from Egypt's mudbrick kilns — the fire that oppressed Israel (Ex 1:14, the brick-kilns) becomes the fire of divine presence. The whole mountain trembled greatly (<em>yecherad kol hahar meod</em>) — the seismic response to divine approach is characteristic of OT theophanies (cf. Ps 68:7-8: 'the earth trembled at the presence of God, the Sinai at the presence of God').</p>",
"19": "<p>The sound of the trumpet grew louder and louder — the escalating intensity of the theophany communicates the approach of the divine: it is not static but dynamic. Moses spoke (<em>yedaber</em>) and God answered him in thunder (<em>baqol</em> — literally 'in a voice/thunder'). The divine speech in thunder is not merely auditory accompaniment but the vehicle of divine communication — the thunder is the divine voice before the articulate words of the Decalogue. Ps 29 meditates on this: 'the voice of YHWH is over the waters... the voice of YHWH breaks the cedars... the voice of YHWH strikes with flashes of lightning.'</p>",
"20": "<p>YHWH descended to the top of Mount Sinai and called Moses to the top — the summit meeting between YHWH (descending from above) and Moses (ascending from below) defines the mediatorial role. Moses ascends and descends multiple times in Ex 19-34; each movement represents a stage in the covenant-making process. The vertical axis of the mountain — divine above, people below, Moses as mediator between — is the spatial expression of the prophetic office. The NT equivalent is Christ as the mediator who descends from the Father and ascends back to him (John 3:13; 20:17).</p>",
"21": "<p>YHWH sends Moses back down to warn the people not to break through (<em>yehershu</em>) to see YHWH — 'lest many of them die.' The warning anticipates the later death of Nadab and Abihu (Lev 10:1-2), Uzzah's death when he touched the ark (2 Sam 6:6-7), and the deaths in Beth-shemesh when they looked into the ark (1 Sam 6:19). Unauthorized approach to the divine presence is not treated as merely offensive but as physically lethal. This is not divine cruelty but the nature of absolute holiness meeting finite, unmediated sinfulness. The tabernacle system, with its graduated access and prescribed atonement, is the divinely provided solution to the problem of human proximity to the holy.</p>",
"22": "<p>Even the priests who come near to YHWH must consecrate themselves — the warning is leveled specifically at those who have designated access. The priests have an institutional right of approach, but even that right requires constant preparation. The principle: rank and title do not substitute for consecration. The NT equivalent is the warning to those who approach the Lord's Supper unworthily (1 Cor 11:27-31) — institutional participation does not guarantee safe approach; the attitude of the heart must correspond to what is received.</p>",
"23": "<p>Moses argues back: the people cannot come up because you yourself commanded barriers around the mountain. The dialogue reveals the frank, negotiating character of the Mosaic relationship with YHWH — Moses is not merely a passive recipient of divine commands but an active mediator who clarifies, argues, and intercedes. This pattern (Moses interceding, debating, reminding YHWH of his own commitments) recurs throughout Ex 32-34 and shapes the OT prophetic tradition of covenantal advocacy before the divine throne.</p>",
"24": "<p>Only Aaron may come up with Moses — but the priests and people must not break through. The three levels of access correspond to the three zones of the tabernacle that will be described in Ex 25-27: people (outer court), priests (holy place), Moses and Aaron (holy of holies). The Sinai theophany is the original template for the tabernacle's spatial theology: the mountain with its zones of access becomes the portable sanctuary with its zones of holiness. Both encode the same theological reality: graduated nearness to the divine presence requires graduated consecration.</p>",
"25": "<p>Moses went down to the people and spoke to them — the closing verse of the preparation completes the pattern. The theophany of ch.20 follows immediately. The narrative structure of ch.19 (preparation, warning, boundary-setting, final descent) mirrors the liturgical preparation for the Levitical feasts: days of preparation precede the moment of divine encounter. The covenant people do not rush into the divine presence; they are prepared, purified, and positioned by a mediator before the encounter occurs.</p>"
},
"20": {
"1": "<p>'And God spoke all these words' — the Decalogue is unique in the OT as direct divine speech to the whole assembled people, not mediated through Moses. Deut 5:4 confirms: 'The LORD spoke with you face to face at the mountain, from the midst of the fire.' In ANE suzerain-vassal treaty form, the great king directly addressed his vassal people: preamble (who I am), historical prologue (what I have done for you), stipulations (what I require), document clause (preserve this covenant), sanctions (blessings and curses). The Decalogue follows this form precisely. Its structure is covenantal-political, not merely ethical: it constitutes a nation under a divine sovereign.</p>",
"2": "<p>'I am YHWH your God who brought you out of Egypt, out of the house of slavery' — the covenant begins with gospel, not law. The historical prologue precedes the stipulations: YHWH's identity as deliverer is the theological foundation of all subsequent commands. Because he is the one who delivered you, these are his expectations. Grace precedes law in the Decalogue's own structure. In ANE suzerain-vassal treaties, the historical prologue typically rehearsed the great king's past benefits to the vassal — the basis for the vassal's obligation. YHWH's prologue is not conquest but redemption: the covenant is not coerced from a defeated enemy but offered to a delivered people.</p>",
"3": "<p>'You shall have no other gods before me (al panai)' — literally 'before my face' or 'in my presence.' The spatial metaphor frames the first commandment as relational: other gods must not occupy the space where YHWH's face is. Whether this prohibits the existence of other gods (philosophical monotheism) or merely their worship (practical monolatry) is a question the text does not resolve directly. The context suggests relational exclusivity: YHWH is Israel's God; other gods are YHWH's rivals, and Israel must not entertain them. The full development of monotheism — other gods are nonentities — comes in Deutero-Isaiah (Isa 44:6-8, 45:5-6) but is implicit in the Sinai covenant's logic.</p>",
"4": "<p>The prohibition of carved images (<em>pesel</em> H6459) and likenesses (<em>temunah</em> H8544) covers all representations: what is in the sky (sun, moon, stars — heavenly bodies worshiped across the ANE), the earth (animals, humans), and the waters below. In the ANE, cult images were not considered to be the gods themselves but their 'presence bearers' — the god inhabited the image and was approachable through it. Egypt's iconography (the Apis bull, falcon-headed Ra, ibis-headed Thoth) was the visual theology Moses left behind. The prohibition targets this entire representational system: YHWH cannot be imaged because he transcends every created category. The prohibition also applies to images of YHWH himself — not just to other gods.</p>",
"5": "<p>YHWH is a 'jealous God' (<em>El qanna</em>, H410 H7067) — the anthropomorphism of divine jealousy is not a human passion projected onto God but a covenantal claim: YHWH will not share the loyalty that is his covenant right. In ANE treaties, the great king demanded exclusive loyalty from his vassals; disloyalty was treachery. YHWH's jealousy is structural: the covenant relationship is exclusive by definition. The visiting of iniquity on the third and fourth generation — not arbitrary punishment but the natural consequence of growing up in a household shaped by idolatry; the children inherit the spiritual distortions of their parents.</p>",
"6": "<p>'Showing covenant love (<em>hesed</em>) to thousands of generations of those who love me and keep my commandments.' The asymmetry of the covenant is stated explicitly: iniquity's effect reaches to the third and fourth generation; <em>hesed</em>'s effect reaches to thousands (of generations). The punishment is finite; the blessing is effectively infinite. The Hebrew word translated 'thousands' (<em>laelaphim</em>) can mean 'thousands of generations' — the covenant mercy vastly outweighs the covenant curse in the divine character.</p>",
"7": "<p>'You shall not lift up the name of YHWH your God for falsehood (<em>shav</em>)' — the third commandment prohibits much more than casual profanity. In the ANE, divine names were invoked in oaths (to bind agreements), in curses (to inflict harm), and in magical incantations (to manipulate divine power). The commandment prohibits all these uses: false oaths in YHWH's name, manipulative curses, and trivial invocations that treat the divine name as a tool. The name YHWH was not merely a label but a compressed disclosure of divine character; to use it lightly was to treat YHWH himself as a means to human ends rather than as the sovereign end in himself.</p>",
"8": "<p>'Remember (<em>zachor</em>) the Sabbath day to keep it holy' — <em>zachor</em> is a performative word: to remember in Hebrew is to act on what is remembered, not merely to recall it cognitively. The Sabbath command in Exodus grounds the seventh-day rest in creation (Gen 2:1-3: YHWH rested on the seventh day). Deuteronomy's parallel (Deut 5:12-15) grounds it in the Exodus ('remember that you were a slave in Egypt'). Both foundations stand: the Sabbath connects creation-order to redemption-history, the rhythm of the cosmos to the experience of liberation. The seventh-day structure pervades biblical thought: Sabbath, Sabbatical year (every 7th year), Jubilee (every 50th year = 7×7+1) — all built on the same foundational rhythm.</p>",
"9": "<p>Six days you shall labor — the Sabbath command includes a positive work ethic: six days of labor are part of the commandment, not just the seventh-day rest. ANE laborers typically had no regular day off; the seven-day week with a day of rest was an innovation of the Mosaic covenant. The rhythm of work and rest encoded in the Sabbath resisted the slave-driver logic of Egypt (constant labor without relief) and inscribed the freedom of the covenant people into their weekly calendar.</p>",
"10": "<p>The rest extends to the entire household: sons, daughters, male and female servants, livestock, and the resident alien (<em>ger</em>) within your gates. The Sabbath is not just a personal benefit but a social institution that protects the most vulnerable members of society — servants and foreigners who have no Sabbath rights of their own in other systems. The inclusion of the <em>ger</em> (sojourner) in Sabbath protection is one of the most socially radical elements of the Mosaic law. The livestock too are protected — the Sabbath rest reaches to the animals, an early expression of the principle that creation itself has rights within the divine order.</p>",
"11": "<p>The creation-based rationale: YHWH made heaven, earth, sea, and all that is in them in six days and rested on the seventh day, therefore he blessed the Sabbath day and made it holy. The Sabbath is inscribed in the structure of creation itself: the seventh day is not a human invention but a divine institution encoded into the fabric of the cosmos from the beginning. Hebrews 4:1-11 develops this: the Sabbath rest of creation is the prototype of the eschatological rest that remains for the people of God, into which the faithful enter through Christ.</p>",
"12": "<p>'Honor (<em>kabed</em> H3513) your father and your mother.' The word <em>kabed</em> means to give weight to, to treat as weighty/significant — the same root as <em>kavod</em> (glory/weightiness). Honoring parents is not merely obedience but the recognition of their significance, their authority, and their claims on the child's loyalty. In ANE household law, the paterfamilias held quasi-divine authority within his household; the fifth commandment extends this to the mother as well, which was unusual. Paul calls this 'the first commandment with a promise' (Eph 6:2): 'so that it may go well with you and that you may have long life in the land.' Land tenure in the covenant is tied to family stability.</p>",
"13": "<p>'You shall not murder (<em>ratzach</em> H7523)' — the specific Hebrew word is <em>ratzach</em>, which refers to unlawful homicide, not killing in general. Israel's law permitted capital punishment (Ex 21:12-14), warfare (Num 31), and the killing of animals for food (Lev 17). The commandment targets intentional, malicious, unauthorized killing of a fellow covenant member. The distinction between <em>ratzach</em> (murder) and <em>harag</em> (kill) is the basis for the cities of refuge (Num 35:9-34), which differentiate between premeditated murder and accidental homicide. Jesus extends this commandment to the interior state: anger is the seed of murder (Matt 5:21-22).</p>",
"14": "<p>'You shall not commit adultery (<em>na'af</em> H5003)' — in ancient Israelite law, adultery was specifically the violation of another man's wife or betrothed; the offending parties were both guilty (Lev 20:10). The social logic: adultery violated the covenantal bond of marriage, introduced uncertainty into genealogical lineage (critical in an inheritance-based land system), and destabilized the household as the foundational social unit. Jesus extends this to the interior: looking at a woman with lustful intent is already adultery in the heart (Matt 5:27-28). The NT elevation of the interior dimension does not replace the external command but exposes its root.</p>",
"15": "<p>'You shall not steal (<em>ganav</em> H1589)' — the range of this commandment extends from property theft to kidnapping (stealing a person — <em>ganav nefesh</em> — is a capital offense in Ex 21:16), to fraud and deceptive business practices (Lev 19:35-36). The principle: every person's rightful possessions — including their own personhood and freedom — are under divine protection. The commandment presupposes legitimate ownership: you may not take what belongs to another, because the covenant establishes each person's rightful sphere. Paul applies it to honest labor: 'let the thief no longer steal... but do honest work' (Eph 4:28).</p>",
"16": "<p>'You shall not bear false witness against your neighbor' — the ninth commandment is specifically judicial in its context: perjury in the covenant court. The covenant community requires reliable testimony for justice to function; false testimony perverts justice and destroys the fabric of social trust. The Mosaic law provides severe penalties for false witnesses (Deut 19:16-21). The broader application to all truth-telling in all contexts is a NT extension (Eph 4:25; Col 3:9), but the original context is the court of justice where human testimony either upholds or destroys the legal order.</p>",
"17": "<p>'You shall not covet (<em>chamad</em> H2530)' — the tenth commandment uniquely targets the interior state rather than an external act. <em>Chamad</em> is the desire for what belongs to another — the same word used when Eve saw that the tree was desirable (<em>nechmad</em>) in Gen 3:6. The commandment prohibits the unchecked desire that leads to the acts prohibited in commandments 6-9: murder, adultery, theft, and false witness all begin with covetous desire. Paul cites this commandment in Rom 7:7-8 as the one that revealed his sin to him: 'I would not have known what covetousness was if the law had not said, do not covet.' The tenth commandment reveals the interior demand of the whole law: not merely external compliance but the transformation of desire.</p>",
"18": "<p>All the people saw the thunder and lightning, the sound of the shofar and the mountain smoking. The verb 'saw' (<em>ro'im</em>) applied to auditory phenomena (thunder, shofar) reflects the synesthetic quality of the theophany — sight and sound are interchangeable in the overwhelming divine presence. The people trembled and stood far off. Their response is the paradigmatic response to divine holiness: awe, terror, and the instinct to maintain distance. The Epistle to the Hebrews (12:18-24) uses this scene to contrast the terrifying Sinai assembly with the heavenly Jerusalem that believers now approach through Christ — the same divine holiness, but accessed through a better Mediator.</p>",
"19": "<p>'Speak to us yourself and we will listen, but do not let God speak to us, or we will die.' The people's request for prophetic mediation is the authorization of the prophetic office. They cannot bear direct divine communication — the people themselves ask for a human intermediary. This grounds the entire institution of prophecy in Israel: Moses, the prophets, and ultimately Christ as the final prophet (Deut 18:15; Acts 3:22) are responses to the people's own request for mediated divine speech. The irony is that the people themselves create the need for the institution that will call them to account.</p>",
"20": "<p>'Do not be afraid; God has come to test you and to put his fear before you so that you will not sin.' The apparent paradox — do not be afraid; this is so you will fear — is resolved by distinguishing between slavish terror (which paralyzes and alienates) and reverential fear (<em>yirat Elohim</em>, which shapes conduct and builds character). The theophanic display is pedagogical: it is calibrated to produce the permanent reverential disposition that prevents sin, not the momentary panic that immobilizes. The fear of God is the beginning of wisdom (Prov 1:7) and the foundation of covenant faithfulness.</p>",
"21": "<p>The people stood far off while Moses approached the thick darkness (<em>araphel</em> H6205) where God was. The thick darkness is the medium of divine concealment that enables presence: YHWH dwells in thick darkness (1 Kings 8:12, Solomon's dedication prayer). The cloud, darkness, and fire are not obstacles to encounter but vehicles of it — they protect the creatures from the lethal exposure to unmediated divine holiness while enabling contact through Moses. The paradox of divine hiddenness and divine presence is encoded in the architecture of Sinai: Moses enters the darkness; the people stay at the boundary.</p>",
"22": "<p>YHWH speaks to Moses about not making gods of silver or gold alongside him — the reinforcement of the second commandment immediately after the Decalogue. The timing is significant: YHWH anticipates the Golden Calf (Ex 32) even as he gives the law against it. The phrase 'gods of silver and gold' (<em>elohei kesef ve-elohei zahav</em>) previews exactly what Aaron will make in Ex 32:4. The commandment is not merely general but speaks directly into the specific temptation that will materialize within forty days.</p>",
"23": "<p>The altar law — an altar of earth (<em>adamah</em> H127) for offerings. The connection of the altar to <em>adamah</em> (earth/soil) ties sacrifice to the creation material from which humans are made (Gen 2:7, Adam from <em>adamah</em>). Sacrifice returns created life to the Creator through the medium of earth. If stone, it must be unhewn — not shaped by an iron tool. The requirement of natural, unworked materials preserves the sense that the altar belongs to YHWH's creation, not to human craft. Iron tools were associated with warfare in the ancient world; the altar of peace must not be shaped by instruments of violence (cf. Deut 27:5; Josh 8:31).</p>",
"24": "<p>The promise: 'In every place where I cause my name to be remembered I will come to you and bless you.' This verse is the theological basis for multiplied worship sites before the centralization of worship in Jerusalem (Deut 12). The patriarchs built altars wherever they encamped — Shechem (Gen 12:7), Bethel (Gen 12:8), Hebron (Gen 13:18) — and these proto-altars are here endorsed: YHWH's name can be remembered (and his blessing received) in multiple locations. The later Deuteronomic centralization at 'the place YHWH will choose' is a development beyond this; the Sinai law allows distributed worship wherever the divine name is present.</p>",
"25": "<p>If you make a stone altar, do not use hewn stones — 'for if you wield your tool upon it you have profaned it.' The negative principle: iron tools desecrate the sacred stone. The Solomonic temple was built at a distance from the quarry, with stone dressed at the quarry so no hammer or chisel was heard at the building site (1 Kings 6:7) — a direct application of this principle to the grandest possible sacred construction. The temple inherits the altar's sanctity requirements.</p>",
"26": "<p>Do not go up to my altar by steps — 'so that your nakedness is not exposed on it.' The altar of the first covenant must not become a site of immodest exposure; the priestly garments that follow (Ex 28) will include linen undergarments specifically to cover nakedness when ascending to the altar (Ex 28:42-43). The concern for bodily modesty before the altar is not prudishness but a form of the holiness principle: the body approaching the divine presence must be appropriately covered. The spatial arrangement of the tabernacle and temple (no external steps to the altar) will incorporate this regulation architecturally.</p>"
},
"21": {
"1": "<p>'These are the ordinances (<em>mishpatim</em>) you are to set before them' — the <em>mishpatim</em> (Ex 21:1-23:33, the Book of the Covenant) are the case-law applications of the Decalogue principles. <em>Mishpat</em> (H4941, judgment/ordinance) is the standard Hebrew term for legal decisions — these are the precedent rulings of a divine court, not arbitrary commands. The phrase 'set before them' suggests presentation for study and internalization, not mere imposition. The Book of the Covenant is the oldest legal code in Israel, and it shares structural parallels with other ANE law codes (Hammurabi, Lipit-Ishtar, the Hittite laws) — using the same conditional case-law form ('if a man does X, then Y') while often applying distinctly different principles.</p>",
"2": "<p>The Hebrew slave law — a Hebrew debt-slave serves six years and goes free in the seventh year. The Sabbath principle is applied to human bondage: just as the land rests every seventh year (Ex 23:11) and the calendar has a weekly day of rest, so human servitude is capped at six years. This law addresses debt slavery (common in the ancient world), not chattel slavery (owning persons as property from birth). The maximum term of six years protects the covenant community's internal equality: Israelites are ultimately YHWH's servants, not each other's property in perpetuity.</p>",
"3": "<p>If the slave came in single, he goes out single; if married, his wife goes with him. The law protects the family unit: the master cannot separate a pre-existing marriage to retain the wife as a slave when the husband goes free. The practical limitation of the master's power over the family reflects the covenant community's value of the family as prior to economic arrangements. The slave had a family before the debt; when the debt is cleared, the family is restored intact.</p>",
"4": "<p>If the master gave the slave a wife and she bore sons and daughters, they remain the master's property. This provision is difficult by modern standards: children born during the term of slavery belong to the household in which they were born. The wife and children are the master's social investment. The next verse (v.5-6) provides the alternative: the slave may choose permanent commitment and keep his family. The law provides no easy exit; the covenant relationship with the family is a binding obligation in both directions.</p>",
"5": "<p>If the slave declares love for his master and does not wish to go free, the choice is presented formally — 'I love my master, my wife, and my children; I will not go free.' The voluntary permanent slave makes an explicit, witnessed declaration. The motivation is relational: love for the household, not economic desperation. This voluntary choice of servitude out of love is the background for the messianic servant passages and for the apostle Paul's self-description as a slave of Christ (Rom 1:1; Phil 1:1) — the one who could be free by right chooses bondage out of love for the master and the household.</p>",
"6": "<p>The ear-piercing at the doorpost — the slave is brought to the doorpost (<em>mezuzah</em>, the same word as the doorpost on which the Shema is affixed, Deut 6:9) and his ear is bored through with an awl. The doorpost marks the boundary of the household; the ear-piercing at the doorpost marks permanent belonging to that household. The ear is pierced because it is the organ of obedience: the slave who listens and obeys is marked as one who permanently belongs to the household of the listening. Ps 40:6 ('ears you have pierced/opened for me') and Heb 10:5-7 apply this imagery christologically to the voluntary self-offering of the Son to the Father's will.</p>",
"7": "<p>A man who sells his daughter as a servant — the female slave law differs because the daughter may be acquired as a potential wife (for the master or his son), not merely as a labor resource. This practice is regulated, not endorsed: the law immediately specifies protections against its abuse. The social context: in an economically precarious household, a father might sell a daughter to a more prosperous household both to relieve his own poverty and to secure a better future for the daughter (by marrying into a stable household). The law now regulates what happens once this arrangement exists.</p>",
"8": "<p>If she does not please the master who designated her for himself, he must let her be redeemed — she cannot be sold to a foreign people. The prohibition against selling to foreigners is the first protection: she is an Israelite woman; her covenant membership limits how she can be disposed of. The right of redemption gives her male relatives (father, brothers) the ability to buy her out of the arrangement. The law is asymmetrical by modern standards but provided genuine protection in its ancient context — she is not merchandise.</p>",
"9": "<p>If he designates her for his son, he shall deal with her as with a daughter — the female slave who becomes the son's wife acquires the full status of a daughter in the household. The son cannot treat her as a sub-wife or second-class wife; her status is elevated to family membership. The principle: the covenant protects the vulnerable from exploitation even within arrangements that carry inherent power asymmetries.</p>",
"10": "<p>If the master takes another wife, he must not diminish the first wife's food, clothing, or marital rights. The law protects the existing wife against being deprioritized when a second wife enters the household. The three protected elements — food, clothing, conjugal rights — are the essential duties of a husband. Paul invokes a similar principle in 1 Cor 7:3-5. The law prevents a man from effectively abandoning his first wife by economic and relational neglect while remaining technically married to her.</p>",
"11": "<p>If the master does not provide these three things for the female slave-wife, she goes out free without any payment — the master's failure of duty releases her from the arrangement without penalty. The law creates a bilateral obligation: the master's rights over the slave-wife are contingent on his fulfilling his duties as a husband. When he fails, her freedom is the consequence. This corrective freedom-grant is a form of the covenant's protection of the vulnerable: the power differential is checked by enforceable obligations.</p>",
"12": "<p>'Anyone who strikes a person so that they die must be put to death' — the capital homicide law. The theological grounding is in Gen 9:6: human life is made in the image of God; its intentional destruction requires the life of the killer. The death penalty for murder is not arbitrary retributive violence but the acknowledgment of human dignity: to kill a human being is to assault the image of God. The law immediately qualifies this with the unintentional-homicide exception (v.13) and the premeditated-murder rule (v.14).</p>",
"13": "<p>If the killing was not premeditated but God allowed it to happen, there is a place of refuge to which the killer may flee. The cities of refuge (developed in Num 35 and Deut 19) are established precisely on this principle: unintentional homicide is legally and morally distinct from murder. The killer who caused accidental death is protected from the avenger of blood (<em>go'el hadam</em>) by reaching a city of refuge. This distinction between murder and manslaughter is maintained in virtually all subsequent Western legal traditions.</p>",
"14": "<p>If a man kills another person intentionally — 'with deliberate forethought' (<em>b'ormah</em> = with cunning/premeditation) — he is to be taken even from the altar and put to death. The altar was traditionally a place of sanctuary (cf. Adonijah and Joab in 1 Kings 1:50; 2:28-34). The exception states that premeditated murder cannot be sheltered even by the sacred precincts. Joab's death at the altar by Solomon's command is the fulfillment of this principle (1 Kings 2:28-34): deliberate murder forfeits the protection of the holy place.</p>",
"15": "<p>Whoever strikes his father or mother shall be put to death — the fifth commandment (honor your parents) receives its maximum sanction. Physical assault on parents is a capital offense because the family is the foundational social institution of the covenant community. In ANE household law, violent insubordination to the paterfamilias was treated as an attack on the entire social order. The principle: a community that cannot maintain the basic relational structures within the family cannot maintain any other social structure either.</p>",
"16": "<p>Anyone who kidnaps a person (<em>gonev ish</em> = steals a man) and sells them or is found with them must be put to death — the first explicit anti-trafficking law in ancient literature. The stealing of a human being as a commodity for sale is a capital crime. The law applies equally whether the trafficker has already sold the victim or is caught in possession — the mere act of trafficking human life carries the death penalty. This principle is absent from Hammurabi's Code, which regulated the slave trade without prohibiting it. The Mosaic law's capital penalty for kidnapping stands in sharp contrast.</p>",
"17": "<p>Whoever curses his father or mother shall be put to death — the verbal counterpart to v.15. Not merely physical assault but the pronouncement of a curse against parents is a capital offense. <em>Qillel</em> (to curse/dishonor) is the antonym of <em>kabed</em> (to honor/give weight to). The fifth commandment stands: honoring parents is not optional, and its opposite is not merely impolite but a crime against the covenant order. Jesus cites this verse to confront the Pharisees' use of <em>qorban</em> (dedicated offerings) as a way of avoiding the financial support of parents — technically legal but spiritually violating this command (Mark 7:10-13).</p>",
"18": "<p>The quarrel injury law — if two men fight and one injures the other but not fatally, and the injured man recovers but is bedridden, the one who struck him is not charged with homicide but must pay for the injured man's lost time and ensure his complete recovery. The first explicit statement of tort liability in ancient law: you are financially responsible for the economic consequences of harm you caused to another person. The compensation covers the two heads of loss: lost income (<em>shivto</em> = his sitting/idleness) and medical expenses (<em>rappo yirapeh</em> = he shall surely cause him to be healed).</p>",
"19": "<p>'Only if the man gets up and walks around outside with the help of his staff will the one who struck him be free from liability — except that he must pay for the loss of his time and see that he is completely healed.' The standard for assessing compensation is recovery and mobility: once the injured man is able to walk with his staff, the primary obligation (full compensation for incapacitation) is discharged, though the attacker remains liable for the ongoing medical costs. This graduated liability anticipates the principle of proportionate compensation that governs all subsequent legal systems.</p>",
"20": "<p>If a man beats his male or female slave with a rod and the slave dies under his hand, he must be punished. The killing of a slave by the master is not exempt from legal consequences — a significant departure from ancient standards in which slaves were typically the unprotected property of their masters. Whether the punishment was death (as for murder) or some lesser penalty is debated; the text says 'avenged (<em>naqom yinaqem</em>)' without specifying the mode. The principle is clear: the slave's life has legal standing; the master does not have unlimited power over it.</p>",
"21": "<p>'But if the slave survives a day or two, the master is not to be punished, for the slave is his money.' This provision acknowledges the economic reality of the slave relationship while providing minimal protection. The rationale that the slave's death represents the master's own economic loss is a recognition of the property relationship, not an endorsement of it. Modern readers rightly find this insufficient protection; the law is a minimum floor, not an ideal ceiling — it is working within an existing institution to limit its worst abuses rather than abolishing the institution entirely (which would happen gradually over the course of redemptive history).</p>",
"22": "<p>If men are fighting and strike a pregnant woman so that she gives birth prematurely but there is no serious injury (<em>ason</em>), the man must pay what the woman's husband demands as assessed by the judges. The term <em>ason</em> (serious harm/injury) is the interpretive crux: if it refers to the mother, the law is about maternal injury; if to the premature infant, it raises questions about the legal status of the unborn. Ancient interpreters divided: the LXX rendered it as distinguishing a formed from an unformed fetus (implying different levels of legal protection); Talmudic interpretation focused primarily on the mother. The verse has been central in contemporary debates about abortion law.</p>",
"23": "<p>But if there is serious injury (<em>ason</em>), then it is life for life — the lex talionis applies. The principle of exact proportionality: the punishment must match the crime precisely, neither more nor less. The lex talionis is often misread as a license for personal revenge; it is in fact a limitation on disproportionate retaliation. In ANE legal practice, punishments for the same offense often varied dramatically by the social status of the parties (a commoner injuring a nobleman might face death; the reverse might bring only a fine). The lex talionis equalizes: the same standard applies regardless of the parties' relative status.</p>",
"24": "<p>Eye for eye, tooth for tooth, hand for hand, foot for foot — the fourfold list articulates the proportionality principle across different categories of injury. Archaeological evidence suggests these provisions were implemented through monetary compensation (the Talmud is explicit that financial equivalence was the practical application) rather than literal physical retaliation. Jesus addresses the lex talionis in Matt 5:38-39 ('You have heard it said, an eye for an eye, but I say to you, do not resist the one who is evil') — he does not abolish the law's justice but transcends it by calling for non-retaliatory response. The kingdom ethic exceeds the legal minimum.</p>",
"25": "<p>Burn for burn, wound for wound, stripe for stripe — the extension of the lex talionis to less severe injuries. Every category of harm has its proportionate consequence; no injury category is exempt from the proportionality principle. The comprehensive list signals that the principle is universal within the covenant community: all harm is subject to proportionate justice, from capital cases (life for life) down to welts and bruises (stripe for stripe). The law creates a total moral economy in which every harmful act has a proportionate cost.</p>",
"26": "<p>If a master knocks out the eye of his male or female slave, he shall let the slave go free on account of the eye. The slave's body is not merely property; injury to the slave's physical person by the master triggers the slave's liberation. The lex talionis principle is adapted for the master-slave relationship: the master cannot lose his eye (that would equalize their social positions), so the slave's freedom compensates for the injury. The principle: the slave's physical integrity has legal standing that, when violated by the master, creates a legal claim. Freedom becomes the <em>kofer</em> (ransom payment) for the lost eye.</p>",
"27": "<p>If a master knocks out a tooth of a male or female slave, the slave goes free for the tooth's sake — the same principle applied to a less severe injury. Even the loss of a single tooth by a slave at the master's hand is sufficient grounds for freedom. The protection of the slave's body is comprehensive: no injury is too minor to trigger the compensation-by-freedom mechanism. This is among the most socially protective provisions in any ancient law code regarding the treatment of enslaved persons by their owners.</p>",
"28": "<p>The goring ox law — one of the most extensively discussed provisions in the Book of the Covenant. If an ox gores a person to death, the ox is stoned and its flesh not eaten. The ox is killed because it has shed human blood (cf. Gen 9:5-6, which extends the blood-guilt principle to animals that kill humans). The flesh is not eaten because the animal has been the instrument of death and is contaminated by blood-guilt. The owner is not held criminally responsible if the ox had no history of dangerous behavior — the first incident establishes the standard of care.</p>",
"29": "<p>If the ox had a history of goring and the owner was warned but did not secure the animal, and the ox then kills a person — both the ox and the owner die. The negligence principle: the owner knew of the risk, failed to act, and that failure caused a death. The owner's culpable negligence makes him a quasi-murderer; his life is forfeit. This principle of liability for foreseeable harm from a known dangerous condition runs through all subsequent Western tort law. The owner who knew and did nothing is morally equivalent to the one who acted with deliberate intent.</p>",
"30": "<p>If the dead person's family accepts a ransom (<em>kofer</em> H3724), the owner may pay it instead of being executed. <em>Kofer</em> is the redemption price, from the root <em>kapar</em> (to cover/atone — the same root as <em>yom kippur</em>). A life can be ransomed by a monetary payment when the parties agree. This ransom principle runs through Israelite theology: the firstborn are ransomed (Ex 13:13-15), the census silver is ransom money (Ex 30:12), and the ultimate ransom of all is the substitutionary atonement of the Suffering Servant (Isa 53:10; Mark 10:45 — the Son of Man gives his life as a <em>lutron</em>, the Greek equivalent of <em>kofer</em>).</p>",
"31": "<p>The goring ox law applies equally whether the victim is a son or daughter — the social status of the victim (child vs. adult) does not change the legal principle. The same ransom mechanism operates. The law applies consistently regardless of age or gender of the victim — a point worth noting against ancient legal systems where the compensation for killing a child (especially a female child) was typically far lower than for an adult male.</p>",
"32": "<p>If the ox gores a male or female slave, the owner must pay thirty shekels of silver to the slave's master. Thirty shekels was the standard price of a slave in the ancient Near East — the standard is also attested in Hittite law. This is the price at which a human life (enslaved) was legally valued. The figure of thirty shekels appears three times in the OT in loaded contexts: here (slave-value), in Zech 11:12-13 (the prophet is contemptuously paid thirty shekels for his labor — the price of a slave — and told to throw it to the potter), and in Matt 26:15 (Judas is paid thirty shekels to betray Jesus). The progression: ox-goring ransom for a slave → contemptuous prophet's wage → the price of the betrayal of the Son of God. The amount that begins as legal compensation ends as theological revelation.</p>",
"33": "<p>The open pit law — if a man opens a pit or digs one and fails to cover it, and an ox or donkey falls in, he must compensate the animal's owner. The principle: you are responsible for hazards you create on your property (or in shared spaces) that cause harm to others. The cistern or pit is not inherently dangerous; the failure to cover it creates the danger. The law applies negligence liability to passive harm (failure to secure against foreseeable risk), not just active harm (the direct blow or the unrestrained dangerous animal).</p>",
"34": "<p>He must pay its value in silver to the owner — the dead animal is his. The liable party pays the fair market value of the animal and receives the carcass (which has some value for hide, meat, and bone). The economic logic is restitutive, not punitive: restore the owner to the position he would have been in if the pit had been covered. ANE law codes show similar principles for cistern liability; the Mosaic law is consistent with the broader ancient legal tradition on this specific point.</p>",
"35": "<p>If one man's ox injures another man's ox and it dies — when there is no prior negligence, the economic loss is shared equally. The owners sell the living ox and divide the proceeds, and they split the dead ox. The absence of negligence triggers cost-sharing rather than full liability: the harm was accidental; both parties bear part of the loss. The distinction between negligent harm (full liability, v.36) and non-negligent harm (shared loss, v.35) is a foundational principle of tort law maintained in legal systems today.</p>",
"36": "<p>If the owner knew that his ox had been dangerous and did not secure it, he must pay an ox for the ox and the dead animal is his. Full restitution for foreseeable harm from a known dangerous condition — the negligence standard. The owner who knew his ox was dangerous and took no precautions bears full responsibility for the consequences. The dead animal goes to the negligent owner: the economic incentive structure reinforces the legal principle — negligence is costly, and the costs fall on the one who was negligent, not the innocent victim.</p>"
}
}

def main():
    data = load_comm('mkt-context', 'exodus')
    merge_comm(data, EXODUS)
    save_comm('mkt-context', 'exodus', data)

    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / 'exodus.json'))
    all_ok = True
    for ch in ['19', '20', '21']:
        il_vv = set(il.get(ch, {}).keys())
        out_vv = set(data.get(ch, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out_vv)} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
